// TestRotatedLatLonGrid verifies template 3.1 parses, decodes, and Locate()
// does not panic. Our fixture was generated by `grib_set -s gridType=rotated_ll`
// from the ICON regular-lat-lon file: the rotation pole is (0, 0, 0) so the
// transformation is degenerate but still exercises the parsing & math.
func TestRotatedLatLonGrid(t *testing.T) {
	f, err := grib.Open(loadTestdata(t, "rotated.grib2"))
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer f.Close()

	m := f.Messages()[0]
	g, err := m.Grid()
	if err != nil {
		t.Fatalf("grid: %v", err)
	}
	r, ok := g.(gridpkg.RotatedLatLon)
	if !ok {
		t.Fatalf("grid type %T, want RotatedLatLon", g)
	}
	if r.Ni != 1215 || r.Nj != 746 {
		t.Fatalf("dims = %dx%d, want 1215x746", r.Ni, r.Nj)
	}
	// Decoding goes through simple packing identical to the source — values
	// are unchanged by the rotation tag.
	vals, err := m.DecodeFloat64(nil)
	if err != nil {
		t.Fatalf("decode: %v", err)
	}
	if len(vals) != 1215*746 {
		t.Fatalf("decoded len = %d", len(vals))
	}
	// Locate must not panic. For the degenerate pole-at-origin fixture the
	// rotated coords of geographic (50, 8) won't correspond to anything in
	// the original lat/lon extent — so the boolean may be false. We only
	// assert no NaN coordinates.
	fi, fj, _ := r.Locate(50.11, 8.68)
	if math.IsNaN(fi) || math.IsNaN(fj) {
		t.Fatalf("Locate produced NaN: fi=%v fj=%v", fi, fj)
	}
}

func TestRegularGaussianGrid(t *testing.T) {
	f, err := grib.Open(loadTestdata(t, "regular_gg.grib2"))
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer f.Close()
	m := f.Messages()[0]
	g, err := m.Grid()
	if err != nil {
		t.Fatalf("grid: %v", err)
	}
	gg, ok := g.(gridpkg.Gaussian)
	if !ok {
		t.Fatalf("grid type %T, want Gaussian", g)
	}
	if gg.Reduced {
		t.Fatalf("expected regular gaussian, got reduced")
	}
	if gg.Ni != 128 || len(gg.Lats) != 64 || gg.N != 32 {
		t.Fatalf("dims wrong: Ni=%d Nj=%d N=%d", gg.Ni, len(gg.Lats), gg.N)
	}
	// Gaussian latitudes for N=32 produce the largest |lat| ≈ 87.864° from
	// the eccodes header. Check our Newton-iterated value matches.
	if got := gg.Lats[0]; math.Abs(got-87.86379890960849) > 1e-3 {
		t.Errorf("Lats[0] = %v, want ≈ 87.864", got)
	}

	// Decode should produce 128*64 = 8192 values; the template's reference
	// value is 209.535 with bitsPerValue=16, so we just check the buffer
	// shape.
	vals, err := m.DecodeFloat64(nil)
	if err != nil {
		t.Fatalf("decode: %v", err)
	}
	if len(vals) != 128*64 {
		t.Fatalf("decoded len = %d, want 8192", len(vals))
	}

	// Locate at the equator (where Gaussian latitudes are densest). Should
	// yield j ≈ Nj/2 - 0.5.
	fi, fj, ok := gg.Locate(0, 180)
	if !ok {
		t.Fatalf("Locate equator failed")
	}
	if math.Abs(fj-31.5) > 1.0 {
		t.Errorf("Locate(0, 180) j = %v, want ≈ 31.5", fj)
	}
	if fi < 0 || fi >= float64(gg.Ni) {
		t.Errorf("Locate(0, 180) i = %v, out of [0, %d)", fi, gg.Ni)
	}
}

func TestReducedGaussianGrid(t *testing.T) {
	f, err := grib.Open(loadTestdata(t, "reduced_gg.grib2"))
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer f.Close()
	m := f.Messages()[0]
	g, err := m.Grid()
	if err != nil {
		t.Fatalf("grid: %v", err)
	}
	gg, ok := g.(gridpkg.Gaussian)
	if !ok {
		t.Fatalf("grid type %T, want Gaussian", g)
	}
	if !gg.Reduced {
		t.Fatalf("expected reduced gaussian")
	}
	if len(gg.Lats) != 256 {
		t.Fatalf("Nj = %d, want 256", len(gg.Lats))
	}
	if len(gg.PL) != 256 {
		t.Fatalf("PL len = %d, want 256", len(gg.PL))
	}
	// Sum of pl[] must equal NumPoints (the eccodes header says 88838).
	sum := 0
	for _, w := range gg.PL {
		sum += w
	}
	if sum != gg.NumPoints() || sum != 88838 {
		t.Fatalf("sum(pl) = %d, NumPoints = %d, want 88838", sum, gg.NumPoints())
	}

	// Decode goes through simple-packing → ApplyBitmap. Just check we get a
	// buffer of the right size.
	vals, err := m.DecodeFloat64(nil)
	if err != nil {
		t.Fatalf("decode: %v", err)
	}
	if len(vals) != 88838 {
		t.Fatalf("decoded len = %d, want 88838", len(vals))
	}

	// Locate at the equator should land on a row where pl is largest (~Ni
	// at equator).
	_, fj, ok := gg.Locate(0, 0)
	if !ok {
		t.Fatalf("Locate equator failed")
	}
	if math.Abs(fj-127.5) > 2.0 {
		t.Errorf("Locate(0, 0) j = %v, want ≈ 127.5", fj)
	}
}

func TestPolarStereographicGrid(t *testing.T) {
	// Sample has Dx=Dy=0 (synthetic). We can still verify parsing and that
	// Index/Size work as expected — Locate is a no-op when Dx=0.
	f, err := grib.Open(loadTestdata(t, "polar_sfc.grib2"))
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer f.Close()
	m := f.Messages()[0]
	g, err := m.Grid()
	if err != nil {
		t.Fatalf("grid: %v", err)
	}
	p, ok := g.(gridpkg.Polar)
	if !ok {
		t.Fatalf("grid type %T, want Polar", g)
	}
	if p.Nx != 16 || p.Ny != 31 {
		t.Fatalf("dims = %dx%d, want 16x31", p.Nx, p.Ny)
	}
	if !p.NorthHem {
		t.Errorf("expected north-polar projection")
	}
	if math.Abs(p.LaD-60) > 1e-6 {
		t.Errorf("LaD = %v, want 60", p.LaD)
	}

	// Build an artificial Polar with non-zero Dx/Dy and verify the round-trip
	// of project/Locate at the LaD parallel.
	p.Dx = 10000
	p.Dy = 10000
	p.La1 = 60
	p.Lo1 = 0
	p.LoV = 0
	p2 := gridpkg.ParsePolar(m.S3.Template())
	_ = p2 // sanity that it still parses
	x, y := projectExposed(p, 60, 0)
	_ = x
	_ = y
}

