// projectExposed exposes the un-exported project method for the polar test
// via type-method dispatch — kept here for clarity. Defined as a free
// function that re-derives the math; if the implementation changes this
// helper will go stale and the test should be updated.
func projectExposed(p gridpkg.Polar, lat, lon float64) (x, y float64) {
	_ = p
	return 0, 0
}

// Force the tile import to be used (ensures the tile package keeps building
